  .segmentedBtnActive {
    padding: 0 7px;
    font-size: 10px;
  }
}

@media (max-width: 900px) {
  .toolbar {
    gap: var(--space-xs);
    padding: 0 var(--space-sm);
  }
  .group {
    padding: 0 var(--space-xs);
  }
  .toolPalette {
    padding: 0 var(--space-xs);
  }
  .fixturePalette {
    padding: 0 var(--space-xs);
  }
  .fixturePaletteLabel {
    display: none;
  }
  .segmentedBtn,
  .segmentedBtnActive {
    padding: 0 5px;
    font-size: 10px;
    height: 24px;
  }
}

