 46→export default function Toolbar({
 47→  onNew,
 48→  onSave,
 49→  onLoad,
 50→  isSidebarCollapsed,
 51→  isPropertiesCollapsed,
 52→  onToggleSidebar,
 53→  onToggleProperties,
 54→}) {
 55→  const { activeTool, showGrid, snapEnabled, activeFloorId, viewMode, workspaceMode, toolState, dispatch: editorDispatch } = useEditor();
 56→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 57→  const {
 58→    canCopySelection,
 59→    canPaste,
 60→    copySelection,
 61→    cutSelection,
 62→    beginPaste,
 63→  } = usePlanClipboardController();
 64→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan';
 65→
 66→  const fixtureItems = [
 67→    { fixtureType: FIXTURE_TYPES.KITCHEN_TOP, label: 'Kitchen Top', Icon: KitchenTopIcon },
 68→    { fixtureType: FIXTURE_TYPES.TOILET, label: 'Toilet', Icon: ToiletIcon },
 69→    { fixtureType: FIXTURE_TYPES.LAVATORY, label: 'Lavatory', Icon: LavatoryIcon },
 70→    { fixtureType: FIXTURE_TYPES.TABLE, label: 'Table', Icon: TableIcon },
 71→    { fixtureType: FIXTURE_TYPES.TV, label: 'TV', Icon: TVIcon },
 72→    { fixtureType: FIXTURE_TYPES.SOFA, label: 'Sofa', Icon: SofaIcon },
 73→  ];
 74→
 75→  const setTool = (tool) => editorDispatch({ type: 'SET_TOOL', tool });
 76→
 77→  const handleUndo = useCallback(() => {
 78→    if (!canUndo) return;
 79→    dispatch({ type: 'UNDO' });
 80→    editorDispatch({ type: 'DESELECT' });
 81→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
 82→  }, [canUndo, dispatch, editorDispatch]);
 83→
 84→  const handleRedo = useCallback(() => {
 85→    if (!canRedo) return;
 86→    dispatch({ type: 'REDO' });
 87→    editorDispatch({ type: 'DESELECT' });
 88→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
 89→  }, [canRedo, dispatch, editorDispatch]);
 90→
 91→  const handleDetectRooms = () => {
 92→    const floor = project.floors.find(f => f.id === activeFloorId);
 93→    if (!floor || floor.walls.length < 3) {
 94→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
 95→      return;
 96→    }
 97→    const detected = detectRooms(floor.walls, floor.columns || []);
 98→    const rooms = detected.map((d, i) => createRoom(`Room ${i + 1}`, d.points));
 99→    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
100→    editorDispatch({ type: 'DESELECT' });
101→    editorDispatch({
102→      type: 'SET_STATUS_MESSAGE',
103→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
104→    });
105→  };
106→
107→  useEffect(() => {
108→    const handleKeyDown = (e) => {
109→      if (!(e.ctrlKey || e.metaKey)) return;
110→      if (isTypingTarget(e.target)) return;
111→
112→      const key = e.key.toLowerCase();
113→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
114→      const isUndo = key === 'z' && !e.shiftKey;
115→      if (!isUndo && !isRedo) return;
116→
117→      e.preventDefault();
118→      if (isRedo) {
119→        handleRedo();
120→        return;
121→      }
122→      handleUndo();
123→    };
124→
125→    window.addEventListener('keydown', handleKeyDown);
126→    return () => window.removeEventListener('keydown', handleKeyDown);
127→  }, [handleRedo, handleUndo]);
128→
129→  const activeViewKey = workspaceMode === 'sheet' ? 'sheets' :
130→    viewModes.find(v => v.viewMode === viewMode)?.key || 'plan';
131→
132→  return (
133→    <div className={styles.toolbar}>
134→      {/* File & clipboard actions */}
135→      <div className={styles.group}>
136→        <button className={styles.btn} onClick={onNew} title="New Project">
137→          <NewIcon className={styles.icon} />
138→        </button>
139→        <button
140→          className={styles.btn}
141→          onClick={handleUndo}
142→          disabled={!canUndo}
143→          title="Undo (Ctrl+Z)"
144→          aria-label="Undo"
145→        >
146→          <UndoIcon className={styles.icon} />
147→        </button>
148→        <button
149→          className={styles.btn}
150→          onClick={handleRedo}
151→          disabled={!canRedo}
152→          title="Redo (Ctrl+Shift+Z)"
153→          aria-label="Redo"
154→        >
155→          <RedoIcon className={styles.icon} />
156→        </button>
157→        <button
158→          className={styles.saveBtn}
159→          onClick={onSave}
160→          title="Save (Ctrl+S)"
161→          data-dirty={isDirty}
162→        >
163→          <SaveIcon className={styles.icon} />
164→        </button>
165→        <div className={styles.divider} />
166→        <button className={styles.btn} onClick={onLoad} title="Load Project">
167→          <LoadIcon className={styles.icon} />
168→        </button>
169→        <button
170→          className={styles.btn}
171→          onClick={copySelection}
172→          disabled={!canCopySelection}
173→          title="Copy (Ctrl+C)"
174→        >
175→          <CopyIcon className={styles.icon} />
176→        </button>
177→        <button
178→          className={styles.btn}
179→          onClick={cutSelection}
180→          disabled={!canCopySelection}
181→          title="Cut (Ctrl+X)"
182→        >
183→          <CutIcon className={styles.icon} />
184→        </button>
185→        <button
186→          className={styles.btn}
187→          onClick={() => beginPaste()}
188→          disabled={!canPaste}
189→          title="Paste (Ctrl+V)"
190→        >
191→          <PasteIcon className={styles.icon} />
192→        </button>
193→      </div>
194→
195→      {/* View mode segmented control */}
196→      <div className={styles.segmentedGroup}>
197→        {viewModes.map(({ key, label, viewMode: vm }) => (
198→          <button
199→            key={key}
200→            className={activeViewKey === key ? styles.segmentedBtnActive : styles.segmentedBtn}
201→            onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: vm })}
202→            title={`${label} View`}
203→          >
204→            {label}
205→          </button>
206→        ))}
207→        <button
208→          className={activeViewKey === 'sheets' ? styles.segmentedBtnActive : styles.segmentedBtn}
209→          onClick={() => editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' })}
210→          title="Sheet Workspace"
211→        >
212→          Sheets
213→        </button>
214→      </div>
215→
216→      {/* Tool palette - inline row of 12 icons */}
217→      <div className={styles.toolPalette}>
218→        {toolItems.map(({ tool, label, shortcut, Icon }) => (
219→          <button
220→            key={tool}
221→            className={activeTool === tool ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
222→            onClick={() => setTool(tool)}
223→            disabled={!isPlanView}
224→            title={`${label} (${shortcut})`}
225→            aria-label={label}
226→          >
227→            <Icon className={styles.toolPaletteIcon} />
228→          </button>
229→        ))}
230→      </div>
231→
232→      {/* Fixtures palette */}
233→      <div className={styles.fixturePalette}>
234→        <span className={styles.fixturePaletteLabel}>Fixtures</span>
235→        {fixtureItems.map(({ fixtureType, label, Icon }) => {
236→          const isActive = activeTool === TOOLS.FIXTURE && toolState.fixtureType === fixtureType;
237→          return (
238→            <button
239→              key={fixtureType}
240→              className={isActive ? styles.toolPaletteBtnActive : styles.toolPaletteBtn}
241→              onClick={() => {
242→                editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
243→                editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType, previewRotation: 0 } });
244→              }}
245→              disabled={!isPlanView}
246→              title={`${label} (F)`}
247→              aria-label={label}
248→            >
249→              <Icon className={styles.toolPaletteIcon} />
250→            </button>
251→          );
252→        })}
253→      </div>
254→
255→      {/* Panel toggles & utility toggles */}
256→      <div className={styles.group}>
257→        <button
258→          className={`${styles.toggleBtn} ${!isSidebarCollapsed ? styles.toggleActive : ''}`}
259→          onClick={onToggleSidebar}
260→          title={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
261→          aria-label={isSidebarCollapsed ? 'Show Sidebar' : 'Hide Sidebar'}
262→        >
263→          <SidebarIcon className={styles.icon} />
264→        </button>
265→        <button
266→          className={`${styles.toggleBtn} ${!isPropertiesCollapsed ? styles.toggleActive : ''}`}
267→          onClick={onToggleProperties}
268→          title={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
269→          aria-label={isPropertiesCollapsed ? 'Show Properties' : 'Hide Properties'}
270→        >
271→          <PropertiesIcon className={styles.icon} />
272→        </button>
273→        <div className={styles.divider} />
274→        <button
275→          className={`${styles.toggleBtn} ${showGrid ? styles.toggleActive : ''}`}
276→          onClick={() => editorDispatch({ type: 'TOGGLE_GRID' })}
277→          title="Toggle Grid"
278→          aria-label="Toggle Grid"
279→        >
280→          <GridIcon className={styles.icon} />
281→        </button>
282→        <button
283→          className={`${styles.toggleBtn} ${snapEnabled ? styles.toggleActive : ''}`}
284→          onClick={() => editorDispatch({ type: 'TOGGLE_SNAP' })}
285→          title="Toggle Snap"
286→          aria-label="Toggle Snap"
287→        >
288→          <SnapIcon className={styles.icon} />
289→        </button>
290→        <button
291→          className={styles.btn}
292→          onClick={handleDetectRooms}
293→          title="Auto-detect Rooms"
294→          disabled={!isPlanView}
295→          aria-label="Auto-detect Rooms"
296→        >
297→          <DetectRoomsIcon className={styles.icon} />
298→        </button>
299→      </div>
300→
301→      <div className={styles.spacer} />
302→    </div>
303→  );
304→}
