 4→export default function FixturePreview({ toolState, activeTool }) {
 5→  if (activeTool !== TOOLS.FIXTURE) return null;
 6→  if (toolState.previewX == null || toolState.previewY == null) return null;
 7→
 8→  const fixtureType = toolState.fixtureType || FIXTURE_TYPES.KITCHEN_TOP;
 9→  const defaults = FIXTURE_DEFAULTS[fixtureType] || { width: 600, depth: 400 };
10→
11→  const preview = {
12→    x: toolState.previewX,
13→    y: toolState.previewY,
14→    width: defaults.width,
15→    depth: defaults.depth,
16→    rotation: toolState.previewRotation || 0,
17→  };
18→
19→  const outline = fixtureOutline(preview);
20→  const points = outline.map(p => `${p.x},${p.y}`).join(' ');
21→
22→  return (
23→    <polygon
24→      points={points}
25→      fill="rgba(200, 180, 160, 0.3)"
26→      stroke="var(--color-selection)"
27→      strokeWidth={2}
28→      strokeDasharray="4 2"
29→      vectorEffect="non-scaling-stroke"
30→      style={{ pointerEvents: 'none' }}
31→    />
32→  );
33→}
