 53→  onToggleProperties,
 54→}) {
 55→  const { activeTool, showGrid, snapEnabled, activeFloorId, viewMode, workspaceMode, toolState, dispatch: editorDispatch } = useEditor();
 56→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 57→  const {
 58→    canCopySelection,
 59→    canPaste,
 60→    copySelection,
 61→    cutSelection,
 62→    beginPaste,
 63→  } = usePlanClipboardController();
 64→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan';
 65→
 66→  const fixtureItems = [
 67→    { fixtureType: FIXTURE_TYPES.KITCHEN_TOP, label: 'Kitchen Top', Icon: KitchenTopIcon },
 68→    { fixtureType: FIXTURE_TYPES.TOILET, label: 'Toilet', Icon: ToiletIcon },
 69→    { fixtureType: FIXTURE_TYPES.LAVATORY, label: 'Lavatory', Icon: LavatoryIcon },
 70→    { fixtureType: FIXTURE_TYPES.TABLE, label: 'Table', Icon: TableIcon },
 71→    { fixtureType: FIXTURE_TYPES.TV, label: 'TV', Icon: TVIcon },
 72→    { fixtureType: FIXTURE_TYPES.SOFA, label: 'Sofa', Icon: SofaIcon },
 73→  ];
 74→
 75→  const setTool = (tool) => editorDispatch({ type: 'SET_TOOL', tool });
 76→
 77→  const handleUndo = useCallback(() => {
 78→    if (!canUndo) return;
 79→    dispatch({ type: 'UNDO' });
 80→    editorDispatch({ type: 'DESELECT' });
 81→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
 82→  }, [canUndo, dispatch, editorDispatch]);
 83→
 84→  const handleRedo = useCallback(() => {
 85→    if (!canRedo) return;
 86→    dispatch({ type: 'REDO' });
 87→    editorDispatch({ type: 'DESELECT' });
 88→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
 89→  }, [canRedo, dispatch, editorDispatch]);
 90→
 91→  const handleDetectRooms = () => {
 92→    const floor = project.floors.find(f => f.id === activeFloorId);
 93→    if (!floor || floor.walls.length < 3) {
 94→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
 95→      return;
 96→    }
 97→    const detected = detectRooms(floor.walls, floor.columns || []);
 98→    const rooms = detected.map((d, i) => createRoom(`Room ${i + 1}`, d.points));
 99→    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
100→    editorDispatch({ type: 'DESELECT' });
101→    editorDispatch({
102→      type: 'SET_STATUS_MESSAGE',
103→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
104→    });
