102→      type: 'SET_STATUS_MESSAGE',
103→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
104→    });
105→  };
106→
107→  useEffect(() => {
108→    const handleKeyDown = (e) => {
109→      if (!(e.ctrlKey || e.metaKey)) return;
110→      if (isTypingTarget(e.target)) return;
111→
112→      const key = e.key.toLowerCase();
113→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
114→      const isUndo = key === 'z' && !e.shiftKey;
115→      if (!isUndo && !isRedo) return;
116→
117→      e.preventDefault();
118→      if (isRedo) {
119→        handleRedo();
120→        return;
121→      }
122→      handleUndo();
123→    };
124→
125→    window.addEventListener('keydown', handleKeyDown);
126→    return () => window.removeEventListener('keydown', handleKeyDown);
127→  }, [handleRedo, handleUndo]);
128→
129→  const activeViewKey = workspaceMode === 'sheet' ? 'sheets' :
130→    viewModes.find(v => v.viewMode === viewMode)?.key || 'plan';
131→
132→  return (
133→    <div className={styles.toolbar}>
134→      {/* File & clipboard actions */}
135→      <div className={styles.group}>
136→        <button className={styles.btn} onClick={onNew} title="New Project">
137→          <NewIcon className={styles.icon} />
138→        </button>
139→        <button
140→          className={styles.btn}
141→          onClick={handleUndo}
142→          disabled={!canUndo}
143→          title="Undo (Ctrl+Z)"
144→          aria-label="Undo"
145→        >
146→          <UndoIcon className={styles.icon} />
147→        </button>
148→        <button
149→          className={styles.btn}
150→          onClick={handleRedo}
151→          disabled={!canRedo}
152→          title="Redo (Ctrl+Shift+Z)"
153→          aria-label="Redo"
154→        >
155→          <RedoIcon className={styles.icon} />
156→        </button>
157→        <button
158→          className={styles.saveBtn}
159→          onClick={onSave}
160→          title="Save (Ctrl+S)"
161→          data-dirty={isDirty}
162→        >
163→          <SaveIcon className={styles.icon} />
164→        </button>
165→        <div className={styles.divider} />
166→        <button className={styles.btn} onClick={onLoad} title="Load Project">
167→          <LoadIcon className={styles.icon} />
168→        </button>
169→        <button
170→          className={styles.btn}
171→          onClick={copySelection}
172→          disabled={!canCopySelection}
173→          title="Copy (Ctrl+C)"
174→        >
175→          <CopyIcon className={styles.icon} />
176→        </button>
177→        <button
178→          className={styles.btn}
179→          onClick={cutSelection}
180→          disabled={!canCopySelection}
181→          title="Cut (Ctrl+X)"
182→        >
183→          <CutIcon className={styles.icon} />
184→        </button>
185→        <button
186→          className={styles.btn}
187→          onClick={() => beginPaste()}
188→          disabled={!canPaste}
189→          title="Paste (Ctrl+V)"
190→        >
191→          <PasteIcon className={styles.icon} />
192→        </button>
193→      </div>
194→
195→      {/* View mode segmented control */}
196→      <div className={styles.segmentedGroup}>
197→        {viewModes.map(({ key, label, viewMode: vm }) => (
198→          <button
199→            key={key}
200→            className={activeViewKey === key ? styles.segmentedBtnActive : styles.segmentedBtn}
201→            onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: vm })}
202→            title={`${label} View`}
